/**
 * projects.js — Projects modal and HomeLab gallery
 * -----------------------------------------------------------------------------
 * ES Module containing:
 *   - Data for all three projects (Scanner / Bank Network / HomeLab) in Arabic and English
 *   - Project icons
 *   - Bank project image (BANK_PROJECT_IMAGE) and GitHub repo link
 *   - HomeLab gallery (HOMELAB_IMAGES + HOMELAB_THUMBNAILS) with autoplay
 *   - Project detail modal with GSAP transitions
 *   - Project-to-project navigation (previous/next)
 *
 * window.onclick functions exposed:
 *   - showProjectModal(index)
 *   - closeProjectModal()
 *   - selectHomelabImage(i, restart)
 *   - stepHomelabGallery(direction)
 *   - navigateProjectCase(direction)
 * -----------------------------------------------------------------------------
 */

import { prefersReducedMotion } from './animations.js';

