let activeProjectIndex = 0;
let projectModalTimeline = null;

const BANK_PROJECT_URL = 'https://github.com/a-almabadi/LAB-NetworkBank';
const BANK_PROJECT_IMAGE = "data:image/jpeg;base64,";
const HOMELAB_IMAGES=["data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,"];;
const HOMELAB_THUMBNAILS=["data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,"];;

let homelabGalleryIndex = 0;
let homelabGalleryTimer = null;

/* ===== Helper: concise copy per project ===== */
function getConciseProjectCopy(index, isArabic) {
    const copy = [
        {
            en: 'A multithreaded Python scanner for TCP and UDP ports with service detection, live progress, and CSV export.',
            ar: 'ماسح منافذ متعدد المسارات بلغة Python يدعم TCP وUDP مع اكتشاف الخدمات والتقدم المباشر وتصدير CSV.',
            impactEn: 'A faster, repeatable workflow for checking ports and exporting results.',
            impactAr: 'آلية أسرع وقابلة للتكرار لفحص المنافذ وتصدير النتائج.'
        },
        {
            en: 'A secure multi-branch bank network designed in Cisco Packet Tracer using routing, SSH, AAA, and NAT.',
            ar: 'شبكة بنك آمنة متعددة الفروع صُممت في Cisco Packet Tracer باستخدام التوجيه وSSH وAAA وNAT.',
            impactEn: 'Secure connectivity between branches and headquarters with controlled administration.',
            impactAr: 'اتصال آمن بين الفروع والمقر الرئيسي مع إدارة وصول محكومة.'
        },
        {
            en: 'A self-hosted lab built with Proxmox and Fedora for private cloud, network services, media, and automation.',
            ar: 'مختبر مستضاف ذاتيًا باستخدام Proxmox وFedora للسحابة الخاصة وخدمات الشبكة والوسائط والأتمتة.',
            impactEn: 'A reliable platform for continuous learning and practical infrastructure operations.',
            impactAr: 'منصة موثوقة للتعلم المستمر والتطبيق العملي لعمليات البنية التحتية.'
        }
    ][index] || {};
    return {
        overview: isArabic ? copy.ar : copy.en,
        impact: isArabic ? copy.impactAr : copy.impactEn
    };
}

/* ===== Per-project visual rendering ===== */
function renderProjectVisual(index, project, isArabic) {
    if (index === 1) return `<div class="project-case-visual project-case-visual--image"><img class="project-case-static-image" src="${BANK_PROJECT_IMAGE}" alt="${isArabic ? 'مخطط شبكة البنك متعددة الفروع' : 'Multi-branch bank network topology'}"></div>`;
    // Network Port Scanner: no placeholder visual — the modal goes straight to the facts.
    if (index !== 2) return '';
    return `<div class="project-case-visual project-case-visual--gallery"><div class="project-homelab-gallery"><div class="project-homelab-stage" onclick="stepHomelabGallery(1)" aria-label="${isArabic ? 'صور المختبر المنزلي' : 'HomeLab gallery'}"><img id="homelab-gallery-main" src="${HOMELAB_IMAGES[0]}" alt="${isArabic ? 'واجهة وإعدادات المختبر المنزلي' : 'HomeLab interface and infrastructure'}" decoding="async"><span id="homelab-gallery-count" class="project-homelab-count">01 / ${String(HOMELAB_IMAGES.length).padStart(2,'0')}</span><span class="project-homelab-controls"><button type="button" class="project-homelab-control" onclick="event.stopPropagation();stepHomelabGallery(-1)" aria-label="Previous image"><i class="fa-solid fa-arrow-left"></i></button><button type="button" class="project-homelab-control" onclick="event.stopPropagation();stepHomelabGallery(1)" aria-label="Next image"><i class="fa-solid fa-arrow-right"></i></button></span></div><div class="project-homelab-thumbs">${HOMELAB_THUMBNAILS.map((src,i)=>`<button type="button" class="project-homelab-thumb${i===0?' is-active':''}" onclick="selectHomelabImage(${i})" aria-label="${isArabic ? `الصورة ${i+1}` : `Image ${i+1}`}"><img src="${src}" alt="" loading="lazy" decoding="async"></button>`).join('')}</div></div></div>`;
}

/* ===== HomeLab gallery ===== */
function selectHomelabImage(index, restart = true) {
    const main = document.getElementById('homelab-gallery-main');
    const count = document.getElementById('homelab-gallery-count');
    if (!main) return;
    homelabGalleryIndex = (index + HOMELAB_IMAGES.length) % HOMELAB_IMAGES.length;
    const update = () => {
        main.src = HOMELAB_IMAGES[homelabGalleryIndex];
        if (count) count.textContent = `${String(homelabGalleryIndex + 1).padStart(2,'0')} / ${String(HOMELAB_IMAGES.length).padStart(2,'0')}`;
        document.querySelectorAll('.project-homelab-thumb').forEach((thumb, i) => thumb.classList.toggle('is-active', i === homelabGalleryIndex));
    };
    if (window.gsap && !prefersReducedMotion()) {
        gsap.to(main, { autoAlpha: 0, duration: .16, onComplete: () => { update(); gsap.to(main, { autoAlpha: 1, duration: .28 }); } });
    } else {
        update();
    }
    if (restart) startHomelabGallery();
}

function stepHomelabGallery(direction) { selectHomelabImage(homelabGalleryIndex + direction); }

function startHomelabGallery() {
    clearInterval(homelabGalleryTimer);
    if (matchMedia('(max-width:640px),(pointer:coarse)').matches) return;
    homelabGalleryTimer = setInterval(() => selectHomelabImage(homelabGalleryIndex + 1, false), 4500);
}

function stopHomelabGallery() {
    clearInterval(homelabGalleryTimer);
    homelabGalleryTimer = null;
}

/* ===== Detect whether to use lightweight motion (mobile / touch / prefers-reduced-motion) ===== */
function useLightweightProjectMotion() {
    return matchMedia('(max-width:640px),(pointer:coarse)').matches || prefersReducedMotion();
}

/* ===== Render modal content ===== */
function renderProjectCase(index) {
    activeProjectIndex = (index + projects.length) % projects.length;
    const project = projects[activeProjectIndex];
    const isAr = window.currentLang === 'ar';
    const concise = getConciseProjectCopy(activeProjectIndex, isAr);
    const previous = projects[(activeProjectIndex - 1 + projects.length) % projects.length];
    const next = projects[(activeProjectIndex + 1) % projects.length];
    const visual = renderProjectVisual(activeProjectIndex, project, isAr);
    const container = document.getElementById('project-modal-content');
    container.innerHTML = `
        <header class="project-case-header">
            <div class="project-case-eyebrow">${isAr ? 'مشروع مختار' : 'Selected Project'} · ${String(activeProjectIndex + 1).padStart(2,'0')}</div>
            <h1 id="project-case-title" class="project-case-title">${isAr ? project.titleAr : project.title}</h1>
            <div class="project-case-context"><strong>${isAr ? project.clientAr : project.client}</strong><span>·</span><span>${isAr ? project.yearAr : project.year}</span></div>
            ${activeProjectIndex === 1 ? `<a class="project-case-link" href="${BANK_PROJECT_URL}" target="_blank" rel="noopener noreferrer"><i class="fa-brands fa-github" aria-hidden="true"></i><span>${isAr ? 'عرض مستودع المشروع' : 'View Project Repository'}</span><i class="fa-solid fa-arrow-up-right-from-square" aria-hidden="true"></i></a>` : ''}
        </header>
        <div class="project-case-layout${visual ? '' : ' project-case-layout--no-visual'}">
            ${visual}
            <aside class="project-case-facts">
                <div class="project-case-fact"><div class="project-case-fact__label">${isAr ? 'الجهة' : 'Organization'}</div><div class="project-case-fact__value">${isAr ? project.clientAr : project.client}</div></div>
                <div class="project-case-fact"><div class="project-case-fact__label">${isAr ? 'المدة' : 'Timeline'}</div><div class="project-case-fact__value">${isAr ? project.yearAr : project.year}</div></div>
                <div class="project-case-fact"><div class="project-case-fact__label">${isAr ? 'المؤشرات' : 'Key Signals'}</div><div class="project-case-fact__value">${(isAr ? project.metricsAr : project.metrics).slice(0,3).join(' · ')}</div></div>
            </aside>
        </div>
        <section class="project-case-section"><div class="project-case-section__label">${isAr ? 'ملخص المشروع' : 'Project Summary'}</div><p>${concise.overview}</p></section>
        <section class="project-case-section"><div class="project-case-section__label">${isAr ? 'التقنيات' : 'Technologies'}</div><div class="project-tech-list">${project.tech.map(item => `<span class="project-tech-item">${item}</span>`).join('')}</div></section>
        <nav class="project-case-navigation" aria-label="${isAr ? 'التنقل بين المشاريع' : 'Project navigation'}">
            <button class="project-case-nav" type="button" onclick="navigateProjectCase(-1)"><small>${isAr ? 'المشروع السابق' : 'Previous Project'}</small><span>${isAr ? previous.titleAr : previous.title}</span></button>
            <button class="project-case-nav" type="button" onclick="navigateProjectCase(1)"><small>${isAr ? 'المشروع التالي' : 'Next Project'}</small><span>${isAr ? next.titleAr : next.title}</span></button>
        </nav>`;
    stopHomelabGallery();
    if (activeProjectIndex === 2) { homelabGalleryIndex = 0; startHomelabGallery(); }
    document.title = isAr ? project.titleAr : project.title;
}

function navigateProjectCase(direction) {
    const reader = document.getElementById('project-reader');
    const content = document.getElementById('project-modal-content');
    const nextIndex = (activeProjectIndex + direction + projects.length) % projects.length;
    if (window.gsap && !useLightweightProjectMotion()) {
        gsap.to(content, { autoAlpha: 0, y: direction > 0 ? -12 : 12, duration: .2, ease: 'power1.in', onComplete: () => {
            renderProjectCase(nextIndex);
            reader.scrollTop = 0;
            gsap.fromTo(content, { autoAlpha: 0, y: direction > 0 ? 16 : -16 }, { autoAlpha: 1, y: 0, duration: .42, ease: 'power2.out', clearProps: 'transform' });
        }});
    } else {
        renderProjectCase(nextIndex);
        reader.scrollTop = 0;
    }
}

/* ===== Open / close the modal ===== */
function showProjectModal(index) {
    const modal = document.getElementById('project-modal');
    const reader = document.getElementById('project-reader');
    renderProjectCase(index);
    projectModalTimeline?.kill();
    modal.classList.remove('hidden');
    modal.classList.add('block');
    reader.scrollTop = 0;
    if (window.gsap && !useLightweightProjectMotion()) {
        projectModalTimeline = gsap.timeline({ onComplete: () => document.getElementById('project-close-button')?.focus() })
            .fromTo(modal, { autoAlpha: 0 }, { autoAlpha: 1, duration: .22, ease: 'power1.out' }, 0)
            .fromTo(reader, { y: 20, scale: .994 }, { y: 0, scale: 1, duration: .48, ease: 'power3.out', clearProps: 'transform' }, .02);
    } else {
        document.getElementById('project-close-button')?.focus();
    }
}

function closeProjectModal() {
    const modal = document.getElementById('project-modal');
    const reader = document.getElementById('project-reader');
    if (!modal || modal.classList.contains('hidden')) return;
    projectModalTimeline?.kill();
    stopHomelabGallery();
    const finish = () => {
        modal.classList.remove('block');
        modal.classList.add('hidden');
        window.gsap?.set(modal, { clearProps: 'opacity,visibility' });
        window.gsap?.set(reader, { clearProps: 'transform,opacity' });
        if (typeof window.updateDocumentMetadata === 'function') {
            window.updateDocumentMetadata(window.currentPageId);
        }
    };
    if (window.gsap && !useLightweightProjectMotion()) {
        projectModalTimeline = gsap.timeline({ onComplete: finish })
            .to(reader, { autoAlpha: .45, y: 10, scale: .996, duration: .2, ease: 'power2.in' }, 0)
            .to(modal, { autoAlpha: 0, duration: .22, ease: 'power1.in' }, .04);
    } else {
        finish();
    }
}

/* ===== Escape key to close the modal ===== */
function initProjects() {
    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') {
            const modal = document.getElementById('project-modal');
            if (modal && !modal.classList.contains('hidden')) {
                closeProjectModal();
            }
        }
        // Navigation arrow keys inside the modal
        const modal = document.getElementById('project-modal');
        if (modal && !modal.classList.contains('hidden')) {
            if (e.key === 'ArrowRight') navigateProjectCase(document.dir === 'rtl' ? -1 : 1);
            else if (e.key === 'ArrowLeft') navigateProjectCase(document.dir === 'rtl' ? 1 : -1);
        }
    });

    // Close on backdrop click
    const modal = document.getElementById('project-modal');
    if (modal) {
        modal.addEventListener('click', (e) => {
            if (e.target === modal || e.target.classList.contains('project-modal-backdrop')) {
                closeProjectModal();
            }
        });
    }
}

/* ===== Expose functions to window for onclick="" handlers ===== */
function exposeGlobals() {
    window.showProjectModal = showProjectModal;
    window.closeProjectModal = closeProjectModal;
    window.selectHomelabImage = selectHomelabImage;
    window.stepHomelabGallery = stepHomelabGallery;
    window.navigateProjectCase = navigateProjectCase;
}

exposeGlobals();

export default initProjects;
export {
    projects,
    activeProjectIndex,
    renderProjectCase,
    showProjectModal,
    closeProjectModal,
    selectHomelabImage,
    stepHomelabGallery,
    navigateProjectCase,
    startHomelabGallery,
    stopHomelabGallery,
    getConciseProjectCopy
};
